module RefModule(
     clk,
     hcount,
     vcount,
     pixel
    );input clk;
    input [10:0] hcount;
    input [9:0] vcount;
    output wire [11:0] pixel;

    reg [11:0]pixel_reg;
    assign pixel=pixel_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt)
    begin
        if ( hcount == 0 || vcount == 30 || hcount == 768 || vcount == 568 )
            pixel_reg <= 12'hFFF;
        else
            pixel_reg <= 12'b0;
    end


endmodule
